  behavior of "solvePart1"

  it should "return the correct number of test occurrences" in {
    val expected = "18"

    solvePart1(testInput) should be(expected)
  }
  it should "return the correct number of real occurrences" in {
    val expected = "2639"

    solvePart1(realInput) should be(expected)
  }

  behavior of "diagonalMatrix"

  it should "return the correct matrix" in {
    forEvery(Table(
      ("matrix", "expected"),
      ("ab\ncd".linesIterator.toSeq, "a\nbc\nd"),
      (turn90Degrees("ab\ncd".linesIterator.toSeq), "b\nda\nc"),
      ("ab\ncd".linesIterator.map(_.reverse).mkString("\n").linesIterator.toSeq, "b\nad\nc")
    )) { (matrix, expected) =>
      diagonalMatrix(matrix) should be(expected)
    }
  }

  behavior of "solvePart2"

  it should "return the correct number of test occurrences" in {
    val expected = "9"

    solvePart2(testInput) should be(expected)
  }
  it should "return the correct number of real occurrences" in {
    val expected = "2005"

    solvePart2(realInput) should be(expected)
  }
}
